kodok = "".join(asu)

if hashlib.sha256(kodok.encode()).hexdigest() != WEBPACK:
    __z()

def from_binary(binary_str):
    return bytes(int(binary_str[i:i+8], 2) for i in range(0, len(binary_str), 8))

lonte = from_binary(kodok)

def GOBLOK(d):
    d = xor(d)
    return base64.b64decode(d)

kontol = GOBLOK(lonte)
memek = GOBLOK(kontol)

exec(memek)
